DROP TABLE IF EXISTS `order_batches`;
CREATE TABLE `order_batches` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `batch_id` char(36) NOT NULL COMMENT '批次UUID',
  `batch_no` varchar(40) NOT NULL COMMENT '批次业务编号',
  `user_id` bigint unsigned NOT NULL COMMENT '用户ID',
  `source_type` varchar(32) NOT NULL DEFAULT 'manual' COMMENT '提交来源类型',
  `submit_mode` varchar(32) NOT NULL DEFAULT 'single' COMMENT '提交模式',
  `raw_content` longtext COMMENT '原始提交内容',
  `estimated_amount` decimal(18,4) NOT NULL DEFAULT '0.0000' COMMENT '预计消费金额',
  `status` varchar(32) NOT NULL DEFAULT 'pending' COMMENT '批次状态',
  `total_count` int unsigned NOT NULL DEFAULT '0' COMMENT '总数量',
  `pending_count` int unsigned NOT NULL DEFAULT '0' COMMENT '待处理数量',
  `processing_count` int unsigned NOT NULL DEFAULT '0' COMMENT '处理中数量',
  `succeeded_count` int unsigned NOT NULL DEFAULT '0' COMMENT '成功数量',
  `failed_count` int unsigned NOT NULL DEFAULT '0' COMMENT '失败数量',
  `retryable_count` int unsigned NOT NULL DEFAULT '0' COMMENT '可重试数量',
  `submitted_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '提交时间',
  `finished_at` datetime DEFAULT NULL COMMENT '完成时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_order_batches_batch_id` (`batch_id`),
  UNIQUE KEY `uk_order_batches_batch_no` (`batch_no`),
  KEY `idx_order_batches_user_created_at` (`user_id`,`created_at`),
  KEY `idx_order_batches_status_submitted_at` (`status`,`submitted_at`)
) ENGINE=InnoDB AUTO_INCREMENT=797 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='订单批次表';
