DROP TABLE IF EXISTS `permissions`;
CREATE TABLE `permissions` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(100) NOT NULL,
  `name` varchar(100) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=9921 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
INSERT INTO `permissions` (`id`,`code`,`name`) VALUES (1,'AC_100100','Common action'),(3,'AC_100110','Create action'),(5,'AC_100120','Update action'),(7,'AC_100010','Read action'),(9,'AC_DASHBOARD_ANALYTICS','Dashboard analytics page'),(11,'AC_DASHBOARD_WORKSPACE','Dashboard workspace page'),(13,'AC_DEMOS_VIEW','Demos pages'),(15,'AC_SYSTEM_ADMIN','System admin pages');
DROP TABLE IF EXISTS `role_permissions`;
CREATE TABLE `role_permissions` (
  `role_id` int unsigned NOT NULL,
  `permission_id` int unsigned NOT NULL,
  PRIMARY KEY (`role_id`,`permission_id`),
  KEY `fk_role_permissions_permission` (`permission_id`),
  CONSTRAINT `fk_role_permissions_permission` FOREIGN KEY (`permission_id`) REFERENCES `permissions` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_role_permissions_role` FOREIGN KEY (`role_id`) REFERENCES `roles` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
INSERT INTO `role_permissions` (`role_id`,`permission_id`) VALUES (1,1),(1,3),(1,5),(1,7),(3,7),(1,9),(1,11),(3,11),(5,11),(1,13),(1,15),(3,15);
DROP TABLE IF EXISTS `roles`;
CREATE TABLE `roles` (
  `id` int unsigned NOT NULL AUTO_INCREMENT,
  `code` varchar(50) NOT NULL,
  `name` varchar(100) NOT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `code` (`code`)
) ENGINE=InnoDB AUTO_INCREMENT=3721 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
INSERT INTO `roles` (`id`,`code`,`name`) VALUES (1,'super','Super Administrator'),(3,'admin','Administrator'),(5,'user','User');
DROP TABLE IF EXISTS `system_configs`;
CREATE TABLE `system_configs` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `config_group` varchar(64) NOT NULL COMMENT '配置分组',
  `config_key` varchar(128) NOT NULL COMMENT '配置键',
  `config_value` json NOT NULL COMMENT '配置值',
  `status` varchar(32) NOT NULL DEFAULT 'active' COMMENT '配置状态',
  `description` varchar(255) DEFAULT NULL COMMENT '配置说明',
  `version` bigint unsigned NOT NULL DEFAULT '1' COMMENT '配置版本',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_system_configs_group_key` (`config_group`,`config_key`)
) ENGINE=InnoDB AUTO_INCREMENT=4769 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='系统配置表';
INSERT INTO `system_configs` (`id`,`config_group`,`config_key`,`config_value`,`status`,`description`,`version`,`created_at`,`updated_at`) VALUES (1,'pricing','view_unit_price',`value` = 0.01,'active','View unit price',1,'2026-05-15 15:40:24.000','2026-05-15 15:40:24.000'),(2,'pricing','impression_unit_price',`value` = 0.01,'active','Impression unit price',1,'2026-05-15 15:40:24.000','2026-05-15 15:40:24.000'),(3,'system','view_submit_enabled',`enabled` = true,'active','Enable view orders',1,'2026-05-15 15:40:24.000','2026-05-15 15:40:24.000'),(4,'system','impression_submit_enabled',`enabled` = true,'active','Enable impression orders',1,'2026-05-15 15:40:24.000','2026-05-15 15:40:24.000');
DROP TABLE IF EXISTS `user_roles`;
CREATE TABLE `user_roles` (
  `user_id` int unsigned NOT NULL,
  `role_id` int unsigned NOT NULL,
  PRIMARY KEY (`user_id`,`role_id`),
  KEY `fk_user_roles_role` (`role_id`),
  CONSTRAINT `fk_user_roles_role` FOREIGN KEY (`role_id`) REFERENCES `roles` (`id`) ON DELETE CASCADE,
  CONSTRAINT `fk_user_roles_user` FOREIGN KEY (`user_id`) REFERENCES `users` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci;
