DROP TABLE IF EXISTS `users`;
CREATE TABLE `users` (
  `id` int unsigned NOT NULL AUTO_INCREMENT COMMENT 'id唯一编号',
  `username` varchar(100) NOT NULL COMMENT '登录用户名',
  `password_hash` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_0900_ai_ci NOT NULL COMMENT '密码',
  `created_at` timestamp NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `real_name` varchar(100) NOT NULL DEFAULT '' COMMENT '真实姓名',
  `home_path` varchar(255) NOT NULL DEFAULT '/analytics' COMMENT '登录后首页路径',
  `user_no` varchar(32) DEFAULT NULL COMMENT '用户业务编号',
  `nickname` varchar(64) DEFAULT NULL COMMENT '用户昵称',
