DROP TABLE IF EXISTS `xhs_query_accounts`;
CREATE TABLE `xhs_query_accounts` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT COMMENT '主键ID',
  `account_no` varchar(40) NOT NULL COMMENT '账号业务编号',
  `account_name` varchar(64) NOT NULL COMMENT '账号备注名称',
  `login_identifier` varchar(128) DEFAULT NULL COMMENT '登录标识',
  `sid_encrypted` text NOT NULL COMMENT '加密后的 SID',
  `cookie_encrypted` longtext COMMENT '加密后的 Cookie',
  `user_agent` varchar(512) DEFAULT NULL COMMENT '请求 User-Agent',
  `proxy_url` varchar(512) DEFAULT NULL COMMENT '代理地址',
  `status` varchar(32) NOT NULL DEFAULT 'active' COMMENT '账号状态',
  `enabled` tinyint(1) NOT NULL DEFAULT '1' COMMENT '是否启用',
  `last_used_at` datetime DEFAULT NULL COMMENT '最近使用时间',
  `next_available_at` datetime DEFAULT NULL COMMENT '下次可用时间',
  `last_success_at` datetime DEFAULT NULL COMMENT '最近成功时间',
  `last_failure_at` datetime DEFAULT NULL COMMENT '最近失败时间',
  `consecutive_failures` int unsigned NOT NULL DEFAULT '0' COMMENT '连续失败次数',
  `success_count` int unsigned NOT NULL DEFAULT '0' COMMENT '成功次数',
  `failure_count` int unsigned NOT NULL DEFAULT '0' COMMENT '失败次数',
  `risk_level` varchar(32) NOT NULL DEFAULT 'normal' COMMENT '风险等级',
  `last_error_code` varchar(64) DEFAULT NULL COMMENT '最近错误编码',
  `last_error_message` varchar(255) DEFAULT NULL COMMENT '最近错误说明',
  `remark` varchar(255) DEFAULT NULL COMMENT '备注',
  `deleted_at` datetime DEFAULT NULL COMMENT '软删除时间',
  `created_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `updated_at` datetime NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`),
  UNIQUE KEY `uk_xhs_query_accounts_account_no` (`account_no`),
  KEY `idx_xhs_query_accounts_status_enabled` (`status`,`enabled`),
  KEY `idx_xhs_query_accounts_next_available_at` (`next_available_at`),
  KEY `idx_xhs_query_accounts_last_used_at` (`last_used_at`),
  KEY `idx_xhs_query_accounts_deleted_at` (`deleted_at`)
) ENGINE=InnoDB AUTO_INCREMENT=1699 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='小红书查询账号池表';
SET FOREIGN_KEY_CHECKS=1;